pub fn guard<G: Guard + 'static>(mut self, guard: G) -> Self {
    self.guards.push(Box::new(guard));
    self
}

pub trait Handler<Args>: Clone + 'static {
    type Output;
    type Future: Future<Output = Self::Output>;

    fn call(&self, args: Args) -> Self::Future;
}

pub fn error_handler<F>(mut self, f: F) -> Self
    where
        F: Fn(JsonPayloadError, &HttpRequest) -> Error + Send + Sync + 'static,
    {
        self.err_handler = Some(Arc::new(f));
        self
    }

#[derive(Clone, Default)]
pub struct PathConfig {
    #[allow(clippy::type_complexity)]
    err_handler: Option<Arc<dyn Fn(PathError, &HttpRequest) -> Error + Send + Sync>>,
}

#[derive(Clone, Default)]
pub struct QueryConfig {
    #[allow(clippy::type_complexity)]
    err_handler: Option<Arc<dyn Fn(QueryPayloadError, &HttpRequest) -> Error + Send + Sync>>,
}

pub fn app_data<U: 'static>(mut self, data: U) -> Self {
    self.app_data
        .get_or_insert_with(Extensions::new)
        .insert(data);

    self
}

pub fn from_fn<F, Es>(mw_fn: F) -> MiddlewareFn<F, Es> {
    MiddlewareFn {
        mw_fn: Rc::new(mw_fn),
        _phantom: PhantomData,
    }
}

pub struct ScopeService {
    router: Router<BoxedHttpService, Vec<Box<dyn Guard>>>,
    default: BoxedHttpService,
}

pub fn route(self, path: &str, mut route: Route) -> Self {
    self.service(
        Resource::new(path)
            .add_guards(route.take_guards())
            .route(route),
    )
}

pub struct RouteService {
    service: BoxService<ServiceRequest, ServiceResponse, Error>,
    guards: Rc<Vec<Box<dyn Guard>>>,
}

pub fn method(mut self, method: Method) -> Self {
    Rc::get_mut(&mut self.guards)
        .unwrap()
        .push(Box::new(guard::Method(method)));
    self
}

pub fn guard<F: Guard + 'static>(mut self, f: F) -> Self {
    Rc::get_mut(&mut self.guards).unwrap().push(Box::new(f));
    self
}

#[must_use]
    pub fn register_input_type<T: InputType>(mut self) -> Self {
        T::create_type_info(&mut self.registry);
        self
    }

pub fn data<D: Any + Send + Sync>(&self) -> Result<&'a D> {
    self.data_opt::<D>().ok_or_else(|| {
        Error::new(format!(
            "Data `{}` does not exist.",
            std::any::type_name::<D>()
        ))
    })
}

pub fn http2_keepalive_interval(self, http2_keepalive_interval: Option<Duration>) -> Self {
    Server {
        http2_keepalive_interval,
        ..self
    }
}

#[cfg(feature = "router")]
#[derive(Clone, Debug)]
pub struct Router<L = Identity> {
    server: Server<L>,
    routes: Routes,
}

impl<T: Endpoint> IntoEndpoint for T {
    type Endpoint = T;

    fn into_endpoint(self) -> Self::Endpoint {
        self
    }
}

impl<E: Endpoint> Middleware<E> for () {
    type Output = E;

    #[inline]
    fn transform(&self, ep: E) -> Self::Output {
        ep
    }
}

#[inline]
    pub fn is_stamped(&self) -> bool {
        self.status_code.is_some_and(|code| {
            code.is_client_error() || code.is_server_error() || code.is_redirection()
        })
    }

impl<'r> FromRequest<'r> for &'r CookieJar<'r> {
    type Error = Infallible;

    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Infallible> {
        Success(request.cookies())
    }
}

#[must_use]
    #[inline(always)]
    pub fn build() -> Self {
        Rocket::custom(Config::figment())
    }

pub fn attach<F: Fairing>(mut self, fairing: F) -> Self {
    self.fairings.add(Box::new(fairing));
    self
}

pub fn routes(&self) -> impl Iterator<Item = &Route> {
    match self.0.as_ref() {
        StateRef::Build(p) => Either::Left(p.routes.iter()),
        StateRef::Ignite(p) => Either::Right(p.router.routes.iter()),
        StateRef::Orbit(p) => Either::Right(p.router.routes.iter()),
    }
}

pub fn state<T: Send + Sync + 'static>(&self) -> Option<&T> {
    match self.0.as_ref() {
        StateRef::Build(p) => p.state.try_get(),
        StateRef::Ignite(p) => p.state.try_get(),
        StateRef::Orbit(p) => p.state.try_get(),
    }
}

pub fn to<U: TryInto<Reference<'static>>>(uri: U) -> Redirect {
    Redirect(Status::SeeOther, uri.try_into().ok())
}

impl<T: Send + Sync + 'static> Deref for State<T> {
    type Target = T;

    #[inline(always)]
    fn deref(&self) -> &T {
        &self.0
    }
}

pub fn figment() -> Figment {
    Figment::from(Config::default())
        .merge(Toml::file(Env::var_or("ROCKET_CONFIG", "Rocket.toml")).nested())
        .merge(Env::prefixed("ROCKET_").ignore(&["PROFILE"]).global())
        .select(Profile::from_env_or("ROCKET_PROFILE", Self::DEFAULT_PROFILE))
}

pub fn try_from<T: Provider>(provider: T) -> Result<Self> {
    let figment = Figment::from(provider);
    let mut config = figment.extract::<Self>()?;
    config.profile = figment.profile().clone();
    Ok(config)
}

pub fn channel<'r, F>(self, handler: F) -> Channel<'r>
        where F: FnOnce(DuplexStream) -> BoxFuture<'r, Result<()>> + Send + 'r
    {
        Channel { ws: self, handler: Box::new(handler), }
    }

pub fn stream<'r, F, S>(self, stream: F) -> MessageStream<'r, S>
        where F: FnOnce(SplitStream<DuplexStream>) -> S + Send + 'r,
              S: futures::Stream<Item = Result<Message>> + Send + 'r
    {
        MessageStream { ws: self, handler: Box::new(stream), }
    }

impl<T> ops::Deref for Json<T> {
